import{_ as e,o as l,c as a,a0 as d}from"./chunks/framework.Bogozrur.js";const x=JSON.parse('{"title":"Schema Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/index.md","filePath":"reference/index.md"}'),o={name:"reference/index.md"};function r(n,t,i,c,h,s){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="schema-reference" tabindex="-1">Schema Reference <a class="header-anchor" href="#schema-reference" aria-label="Permalink to &quot;Schema Reference&quot;">​</a></h1><p><code>SV::object()</code> に渡すフィールド定義の全表現を一覧する。</p><p>各表現は JSON Schema draft 2020-12 のキーワードに対応し、サーバー側バリデーション（Respect/Validation）とクライアント側バリデーション（SDK / Zod）の両方に適用される。</p><hr><h2 id="フィールド型" tabindex="-1">フィールド型 <a class="header-anchor" href="#フィールド型" aria-label="Permalink to &quot;フィールド型&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">表現</th><th style="text-align:left;">JSON Schema <code>type</code></th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./string.html"><code>SV::string()</code></a></td><td style="text-align:left;"><code>&quot;string&quot;</code></td><td style="text-align:left;">テキスト入力。長さ・形式・正規表現の制約を持てる</td></tr><tr><td style="text-align:left;"><a href="./number.html"><code>SV::integer()</code></a></td><td style="text-align:left;"><code>&quot;integer&quot;</code></td><td style="text-align:left;">整数。範囲制約を持てる</td></tr><tr><td style="text-align:left;"><a href="./number.html"><code>SV::number()</code></a></td><td style="text-align:left;"><code>&quot;number&quot;</code></td><td style="text-align:left;">整数または小数。範囲制約を持てる</td></tr><tr><td style="text-align:left;"><a href="./scalar.html"><code>SV::boolean()</code></a></td><td style="text-align:left;"><code>&quot;boolean&quot;</code></td><td style="text-align:left;">真偽値</td></tr><tr><td style="text-align:left;"><a href="./scalar.html"><code>SV::enum(values)</code></a></td><td style="text-align:left;"><code>&quot;string&quot;</code> + <code>enum</code></td><td style="text-align:left;">選択肢から1つを選ぶ</td></tr><tr><td style="text-align:left;"><a href="./extended.html"><code>SV::file(accept)</code></a></td><td style="text-align:left;">—（JSON Schema 非対応）</td><td style="text-align:left;">ファイルアップロード</td></tr><tr><td style="text-align:left;"><a href="./extended.html"><code>SV::respect(rule)</code></a></td><td style="text-align:left;">—（JSON Schema 非対応）</td><td style="text-align:left;">Respect/Validation ルールの直接指定</td></tr></tbody></table><h2 id="文字列制約" tabindex="-1">文字列制約 <a class="header-anchor" href="#文字列制約" aria-label="Permalink to &quot;文字列制約&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">表現</th><th style="text-align:left;">JSON Schema キーワード</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./string.html#min"><code>.min(n)</code></a></td><td style="text-align:left;"><code>minLength</code></td><td style="text-align:left;">最小文字数</td></tr><tr><td style="text-align:left;"><a href="./string.html#max"><code>.max(n)</code></a></td><td style="text-align:left;"><code>maxLength</code></td><td style="text-align:left;">最大文字数</td></tr><tr><td style="text-align:left;"><a href="./string.html#email"><code>.email()</code></a></td><td style="text-align:left;"><code>format: &quot;email&quot;</code></td><td style="text-align:left;">メールアドレス形式</td></tr><tr><td style="text-align:left;"><a href="./string.html#url"><code>.url()</code></a></td><td style="text-align:left;"><code>format: &quot;uri&quot;</code></td><td style="text-align:left;">URL 形式</td></tr><tr><td style="text-align:left;"><a href="./string.html#pattern"><code>.pattern(p)</code></a></td><td style="text-align:left;"><code>pattern</code></td><td style="text-align:left;">正規表現</td></tr></tbody></table><h2 id="数値制約" tabindex="-1">数値制約 <a class="header-anchor" href="#数値制約" aria-label="Permalink to &quot;数値制約&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">表現</th><th style="text-align:left;">JSON Schema キーワード</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./number.html#min"><code>.min(n)</code></a></td><td style="text-align:left;"><code>minimum</code></td><td style="text-align:left;">最小値</td></tr><tr><td style="text-align:left;"><a href="./number.html#max"><code>.max(n)</code></a></td><td style="text-align:left;"><code>maximum</code></td><td style="text-align:left;">最大値</td></tr></tbody></table><h2 id="修飾子" tabindex="-1">修飾子 <a class="header-anchor" href="#修飾子" aria-label="Permalink to &quot;修飾子&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">表現</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./modifiers.html#optional"><code>.optional()</code></a></td><td style="text-align:left;"><code>required</code> 配列から除外。未入力を許容する</td></tr><tr><td style="text-align:left;"><a href="./modifiers.html#nullable"><code>.nullable()</code></a></td><td style="text-align:left;"><code>type</code> を <code>[type, &quot;null&quot;]</code> に拡張。<code>null</code> 値を許容する</td></tr></tbody></table><h2 id="オブジェクト・出力" tabindex="-1">オブジェクト・出力 <a class="header-anchor" href="#オブジェクト・出力" aria-label="Permalink to &quot;オブジェクト・出力&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">表現</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./object.html#object"><code>SV::object(fields)</code></a></td><td style="text-align:left;">フィールドの集合を定義する</td></tr><tr><td style="text-align:left;"><a href="./object.html#tojsonschema"><code>.toJsonSchema()</code></a></td><td style="text-align:left;">JSON Schema (array) として出力</td></tr><tr><td style="text-align:left;"><a href="./object.html#tojson"><code>.toJson()</code></a></td><td style="text-align:left;">JSON Schema (string) として出力</td></tr><tr><td style="text-align:left;"><a href="./object.html#tovalidator"><code>.toValidator()</code></a></td><td style="text-align:left;">Respect/Validation ベースの <code>Validator</code> を生成</td></tr></tbody></table>',14)])])}const g=e(o,[["render",r]]);export{x as __pageData,g as default};
